resource "aws_security_group" "database" {
  name        = "${local.project}-${local.environment}-database"
  description = "Database security group"
  vpc_id      = aws_vpc.main.id

  ingress {
    description     = "PostgreSQL from public application server"
    from_port       = 5432
    to_port         = 5432
    protocol        = "tcp"
